from __future__ import annotations
import argparse,json,sys
from pathlib import Path
ROOT=Path(__file__).resolve().parents[3];sys.path.insert(0,str(ROOT))
from tools.quality.flora.usda_common import canonical_hash,validate,write_json,sha256_file
p=argparse.ArgumentParser();p.add_argument('--join-plan',type=Path,required=True);p.add_argument('--county-geojson',type=Path,required=True);p.add_argument('--county-presence',type=Path,required=True);p.add_argument('--geometry-approval',type=Path,required=True);p.add_argument('--out-root',type=Path,required=True);p.add_argument('--snapshot-date',required=True);p.add_argument('--generated-at',required=True);a=p.parse_args()
