r={"schema_version":"1.0.0","object_type":"usda_plants_geometry_publication_receipt","geometry_publication_receipt_id":f"kfm.geometry_publication_receipt.flora.usda_plants.{a.snapshot_date}","domain":"flora","source_id":"usda_plants","snapshot_date":a.snapshot_date,"generated_at":a.generated_at,"join_plan_ref":str(a.join_plan),"published_items":[{"role":"county_presence_geojson","target_ref":f"published/flora/usda_plants/{a.snapshot_date}/map/county_presence.geojson","sha256":sha256_file(out/'county_presence.geojson'),"status":"published"}],"publication_state":"published","status":"pass","reason_codes":[]}
r['receipt_hash']=canonical_hash(r,'receipt_hash');write_json(a.out_root/f'geometry/flora/usda_plants/{a.snapshot_date}/geometry_publication_receipt.json',r)
